function expensive() { calls++; return calls; }
// 模擬三次渲染：直接呼叫的版本，每次渲染都執行
for (let render = 0; render < 3; render++) {
  expensive();
}
console.log(calls);

let calls = 0;
function expensive() { calls++; return calls; }
// 模擬三次渲染：只傳函式本身，只在「首次渲染」才呼叫
let initialized = false;
for (let render = 0; render < 3; render++) {
  if (!initialized) {
    expensive();
    initialized = true;
  }
}
console.log(calls);

